        swap_count = 0
        n = len(row)
        for i in range(0, n, 2):
            if (row[i+1] == row[i] ^ 1):
                continue
            partner = row[i] ^ 1
            for j in range(i+1, n):
                if row[j] == partner:
                    break
            row[i+1], row[j] = row[j], row[i+1]
            swap_count += 1
